with deleted_firing as (
  delete from public.glaze_firing_images
  where glaze_id in (
    select id
    from public.glazes
    where brand = 'Clay Art Center' and created_by_user_id is null
  )
), deleted_glazes as (
  delete from public.glazes
  where brand = 'Clay Art Center' and created_by_user_id is null
)
